SET @index_exists = (SELECT COUNT(*) FROM information_schema.STATISTICS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'desastres' AND INDEX_NAME = 'idx_desastres_ubm');
SET @sql = IF(@index_exists = 0, 'ALTER TABLE desastres ADD INDEX idx_desastres_ubm (ubm_id)', 'SELECT 1');
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;

SET @index_exists = (SELECT COUNT(*) FROM information_schema.STATISTICS WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'desastres' AND INDEX_NAME = 'idx_desastres_compdec');
SET @sql = IF(@index_exists = 0, 'ALTER TABLE desastres ADD INDEX idx_desastres_compdec (compdec_id)', 'SELECT 1');
PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;

SET @fk_desastres_compdec_exists = (
    SELECT COUNT(*)
    FROM information_schema.TABLE_CONSTRAINTS
    WHERE CONSTRAINT_SCHEMA = DATABASE()
      AND TABLE_NAME = 'desastres'
      AND CONSTRAINT_NAME = 'fk_desastres_compdec'
);
SET @fk_desastres_compdec_sql = IF(
    @fk_desastres_compdec_exists = 0,
    'ALTER TABLE desastres ADD CONSTRAINT fk_desastres_compdec FOREIGN KEY (compdec_id) REFERENCES compdecs(id) ON UPDATE CASCADE ON DELETE SET NULL',
    'SELECT 1'
);
PREPARE fk_desastres_compdec_stmt FROM @fk_desastres_compdec_sql;
EXECUTE fk_desastres_compdec_stmt;
DEALLOCATE PREPARE fk_desastres_compdec_stmt;
DELETE FROM compdecs;

ALTER TABLE compdecs AUTO_INCREMENT = 433;

DELETE FROM ubms WHERE descricao IN ('Fonte: Multirriscos COMPDEC', 'Fonte: COMPDEC DGD');

SELECT m.id, NULL, c.ubm_nome, 'Fonte: COMPDEC DGD', 1
FROM compdecs c
INNER JOIN municipios m ON m.codigo_ibge = CAST(c.municipio_codigo AS UNSIGNED)
LEFT JOIN ubms existente ON existente.municipio_id = m.id AND existente.nome = c.ubm_nome
WHERE c.ubm_nome IS NOT NULL
  AND TRIM(c.ubm_nome) <> ''
  AND existente.id IS NULL;